import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { getAllRFQs } from "../api/axios";

const statusBadge = (status) => {
  const badges = {
    active: { bg: "bg-gradient-to-r from-emerald-50 to-teal-50", border: "border-emerald-200", text: "text-emerald-700", icon: "🟢" },
    force_closed: { bg: "bg-gradient-to-r from-red-50 to-pink-50", border: "border-red-200", text: "text-red-700", icon: "🔴" },
    closed: { bg: "bg-gradient-to-r from-gray-50 to-slate-50", border: "border-gray-200", text: "text-gray-700", icon: "⭕" },
  };
  const badge = badges[status] || badges.closed;
  const label = status === "active" ? "Active" : status === "force_closed" ? "Force Closed" : "Closed";
  return (
    <span className={`inline-flex items-center space-x-1 px-3 py-1.5 rounded-full text-sm font-semibold ${badge.bg} ${badge.border} ${badge.text} border`}>
      <span>{badge.icon}</span>
      <span>{label}</span>
    </span>
  );
};

const formatDateTime = (dt) => {
  if (!dt) return "";
  const d = new Date(dt);
  return d.toLocaleString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
};

const AuctionList = () => {
  const navigate = useNavigate();
  const [rfqs, setRfqs] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchRFQs = async () => {
    setLoading(true);
    try {
      const data = await getAllRFQs();
      setRfqs(data);
    } catch (e) {
      setRfqs([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRFQs();
    const interval = setInterval(fetchRFQs, 30000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="min-h-screen py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-12">
          <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-4">
            <div>
              <h1 className="text-4xl font-bold text-gray-900 mb-2">Active Auctions</h1>
              <p className="text-gray-600">Manage and monitor all your RFQ auctions</p>
            </div>
            <button
              className="mt-4 sm:mt-0 bg-gradient-to-r from-blue-600 to-cyan-600 text-white font-semibold px-6 py-3 rounded-lg hover:from-blue-700 hover:to-cyan-700 transition shadow-lg hover:shadow-xl flex items-center space-x-2"
              onClick={() => navigate("/create-rfq")}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
              <span>Create New RFQ</span>
            </button>
          </div>
          <div className="h-1 w-20 bg-gradient-to-r from-blue-500 to-cyan-500 rounded"></div>
        </div>

        {/* Loading State */}
        {loading && (
          <div className="flex flex-col items-center justify-center py-24">
            <svg className="animate-spin h-12 w-12 text-blue-600 mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8z"></path></svg>
            <p className="text-gray-500 font-medium">Loading auctions...</p>
          </div>
        )}

        {/* Empty State */}
        {!loading && rfqs.length === 0 && (
          <div className="text-center py-24">
            <div className="mb-4">
              <svg className="mx-auto h-16 w-16 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4" /></svg>
            </div>
            <h3 className="text-lg font-semibold text-gray-900 mb-2">No Auctions Yet</h3>
            <p className="text-gray-500 mb-6">Create your first RFQ to get started</p>
            <button
              className="bg-gradient-to-r from-blue-600 to-cyan-600 text-white font-semibold px-6 py-2.5 rounded-lg hover:from-blue-700 hover:to-cyan-700 transition"
              onClick={() => navigate("/create-rfq")}
            >
              Create First RFQ
            </button>
          </div>
        )}

        {/* Cards Grid */}
        {!loading && rfqs.length > 0 && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {rfqs.map((rfq) => (
              <div
                key={rfq.id}
                className="bg-white rounded-xl shadow-md hover:shadow-xl transition-all duration-300 overflow-hidden group cursor-pointer transform hover:-translate-y-1"
                onClick={() => navigate(`/rfq/${rfq.id}`)}
              >
                {/* Top accent bar */}
                <div className="h-1 bg-gradient-to-r from-blue-500 via-cyan-400 to-blue-500"></div>

                <div className="p-6">
                  {/* Header with Status */}
                  <div className="flex items-start justify-between mb-4">
                    <div className="flex-1">
                      <h3 className="text-lg font-bold text-gray-900 group-hover:text-blue-600 transition line-clamp-2">
                        {rfq.name}
                      </h3>
                      <p className="text-sm text-gray-500 font-mono mt-1">ID: {rfq.reference_id}</p>
                    </div>
                    <div className="ml-3">
                      {statusBadge(rfq.status)}
                    </div>
                  </div>

                  {/* Divider */}
                  <div className="h-px bg-gray-100 mb-4"></div>

                  {/* Content Grid */}
                  <div className="grid grid-cols-2 gap-4 mb-4">
                    {/* Lowest Bid */}
                    <div className="bg-gradient-to-br from-green-50 to-emerald-50 rounded-lg p-3 border border-green-100">
                      <p className="text-xs font-semibold text-gray-600 mb-1">Current Low Bid</p>
                      {rfq.lowest_bid == null ? (
                        <p className="text-lg font-bold text-gray-400">-</p>
                      ) : (
                        <p className="text-xl font-bold text-green-700">£{rfq.lowest_bid.toFixed(2)}</p>
                      )}
                    </div>

                    {/* Bid Close Time */}
                    <div className="bg-gradient-to-br from-blue-50 to-cyan-50 rounded-lg p-3 border border-blue-100">
                      <p className="text-xs font-semibold text-gray-600 mb-1">Closes</p>
                      <p className="text-sm font-mono text-blue-700">{formatDateTime(rfq.bid_close_time)}</p>
                    </div>
                  </div>

                  {/* Forced Close Info */}
                  <div className="bg-gray-50 rounded-lg p-3 border border-gray-100 mb-4">
                    <p className="text-xs font-semibold text-gray-600 mb-1">Force Closes</p>
                    <p className="text-sm font-mono text-gray-700">{formatDateTime(rfq.forced_close_time)}</p>
                  </div>

                  {/* View Button */}
                  <button
                    className="w-full bg-gradient-to-r from-blue-600 to-cyan-600 text-white font-semibold py-2.5 rounded-lg hover:from-blue-700 hover:to-cyan-700 transition group-hover:shadow-lg"
                    onClick={(e) => {
                      e.stopPropagation();
                      navigate(`/rfq/${rfq.id}`);
                    }}
                  >
                    View Details →
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default AuctionList;
